/*
 * @method
 * @name coinone#watchOrderBook
 * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
 * @see https://docs.coinone.co.kr/reference/public-websocket-orderbook
 * @param {string} symbol unified symbol of the market to fetch the order book for
 * @param {int} [limit] the maximum amount of order book entries to return
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
 */
    pub async fn watch_order_book(&mut self, mut symbol: Value, optional_args: &[Value]) -> Value {
        let mut limit = get_arg(optional_args, 0, Value::Null);
        let mut params = get_arg(optional_args, 1, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        if is_equal(&self.markets, &Value::Null) {
            self.load_markets(&[]).await;
        }
        let mut market: Value = self.market(symbol.clone());
        let mut messageHash: Value = add(&Value::Str("orderbook:".to_string()), &get_value(&market, &Value::Str("symbol".to_string())));
        let mut url: Value = get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &Value::Str("ws".to_string()));
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("request_type".to_string(), Value::Str("SUBSCRIBE".to_string()));
                m.insert("channel".to_string(), Value::Str("ORDERBOOK".to_string()));
                m.insert("topic".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("quote_currency".to_string(), get_value(&market, &Value::Str("quote".to_string())));
        m.insert("target_currency".to_string(), get_value(&market, &Value::Str("base".to_string())));
    m
}));
            m
        });
        let mut message: Value = self.extend(request.clone(), &[params.clone()]);
        let mut orderbook: Value = self.watch(url.clone(), messageHash.clone(), &[message.clone(), messageHash.clone()]).await;
        return orderbook.limit();

    Value::Null
}

    pub fn handle_order_book(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "response_type": "DATA",
        //         "channel": "ORDERBOOK",
        //         "data": {
        //             "quote_currency": "KRW",
        //             "target_currency": "BTC",
        //             "timestamp": 1705288918649,
        //             "id": "1705288918649001",
        //             "asks": [
        //                 {
        //                     "price": "58412000",
        //                     "qty": "0.59919807"
        //                 }
        //             ],
        //             "bids": [
        //                 {
        //                     "price": "58292000",
        //                     "qty": "0.1045"
        //                 }
        //             ]
        //         }
        //     }
        //
        let mut data: Value = self.safe_value_k(message.clone(), "data", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut baseId: Value = self.safe_string_upper(data.clone(), Value::Str("target_currency".to_string()), &[]);
        let mut quoteId: Value = self.safe_string_upper(data.clone(), Value::Str("quote_currency".to_string()), &[]);
        let mut base: Value = self.safe_currency_code(baseId.clone(), &[]);
        let mut quote: Value = self.safe_currency_code(quoteId.clone(), &[]);
        let mut symbol: Value = self.symbol(add(&add(&base, &Value::Str("/".to_string())), &quote));
        let mut timestamp: Value = self.safe_integer_k(data.clone(), "timestamp", &[]);
        let mut orderbook: Value = self.safe_value(self.orderbooks.clone(), symbol.clone(), &[]);
        if is_equal(&orderbook, &Value::Null) {
            orderbook = self.order_book(&[]);
        }  else {
            orderbook.reset0();
        }
        add_element_to_object(&mut orderbook, &Value::Str("symbol".to_string()), symbol.clone());
        let mut asks: Value = self.safe_value_k(data.clone(), "asks", &[Value::List(vec![])]);
        let mut bids: Value = self.safe_value_k(data.clone(), "bids", &[Value::List(vec![])]);
        self.handle_deltas(get_value(&orderbook, &Value::Str("asks".to_string())), asks.clone());
        self.handle_deltas(get_value(&orderbook, &Value::Str("bids".to_string())), bids.clone());
        add_element_to_object(&mut orderbook, &Value::Str("timestamp".to_string()), timestamp.clone());
        add_element_to_object(&mut orderbook, &Value::Str("datetime".to_string()), self.iso8601(timestamp.clone()));
        let mut messageHash: Value = add(&Value::Str("orderbook:".to_string()), &symbol);
        add_element_to_object(&mut self.orderbooks.clone(), &symbol, orderbook.clone());
        client.resolve(&[orderbook.clone(), messageHash.clone()]);
}

    pub fn handle_delta(&self, mut bookside: Value, mut delta: Value) {
        let mut bidAsk: Value = self.parse_order_book_bid_ask(delta.clone(), &[Value::Str("price".to_string()), Value::Str("qty".to_string())]);
        bookside.store_array(bidAsk.clone());
}

